+fn test_symbol(
+    object_id: ObjectId,
+    zone_id: ZoneId,
+    esi: u32,
+    source_node: u64,
+    symbol_size: usize,
+) -> StoredSymbol {
+    let esi_byte = u8::try_from(esi).unwrap_or(0xFF);
+    StoredSymbol {
+        meta: fcp_store::SymbolMeta {
+            object_id,
+            esi,
+            zone_id,
+            source_node: Some(source_node),
+            stored_at: 0,
+        },
+        data: Bytes::from(vec![esi_byte; symbol_size]),
+    }
+}
