+    for esi in 0..meta.source_symbols {
+        harness
+            .store_symbol(&node, test_symbol(object_id, zone_id.clone(), esi, 1, 64))
+            .await
+            .unwrap();
+    }
+
+    assert!(harness.can_reconstruct(&node, object_id).await.unwrap());
+    harness.shutdown().await.unwrap();
+}
